      'isQueuedForPrint?: boolean;',
      'itemGroupLines?: { itemGroupId: string; customFields?: { name: string; ownerId: string; value: string; }[]; inventorySiteId?: string; inventorySiteLocationId?: string; quantity?: number; unitOfMeasure?: string; }[];',
      "itemLines?: { amount?: string; billingStatus?: 'billable' | 'has_been_billed' | 'not_billable'; classId?: string; cost?: string; customerId?: string; customFields?: { name: string; ownerId: string; value: string; }[]; description?: string; expirationDate?: string; inventorySiteId?: string; inventorySiteLocationId?: string; itemId?: string; linkToTransactionLine?: { transactionId: string; transactionLineId: string; }; lotNumber?: string; overrideItemAccountId?: string; quantity?: number; salesRepresentativeId?: string; salesTaxCodeId?: string; serialNumber?: string; unitOfMeasure?: string; }[];",
