      'salesTaxItemId?: string;',
      'shipmentOrigin?: string;',
      'shippingAddress?: { city?: string; country?: string; line1?: string; line2?: string; line3?: string; line4?: string; line5?: string; note?: string; postalCode?: string; state?: string; };',
      'shippingDate?: string;',
