      "lines?: { id: string; amount?: string; classId?: string; description?: string; inventorySiteId?: string; inventorySiteLocationId?: string; itemId?: string; lotNumber?: string; otherCustomField1?: string; otherCustomField2?: string; overrideItemAccountId?: string; overrideUnitOfMeasureSetId?: string; priceLevelId?: string; priceRuleConflictStrategy?: 'base_price' | 'zero'; quantity?: number; rate?: string; ratePercent?: string; salesTaxCodeId?: string; serialNumber?: string; serviceDate?: string; unitOfMeasure?: string; }[];",
