      "itemGroupLines?: { id: string; itemGroupId?: string; itemLines?: { id: string; amount?: string; billingStatus?: 'billable' | 'has_been_billed' | 'not_billable'; classId?: string; cost?: string; customerId?: string; description?: string; expirationDate?: string; inventorySiteId?: string; inventorySiteLocationId?: string; itemId?: string; lotNumber?: string; overrideItemAccountId?: string; overrideUnitOfMeasureSetId?: string; quantity?: number; salesRepresentativeId?: string; salesTaxCodeId?: string; serialNumber?: string; unitOfMeasure?: string; }[]; overrideUnitOfMeasureSetId?: string; quantity?: number; unitOfMeasure?: string; }[];",
