      'isActive?: boolean;',
      'parentId?: string;',
      'salesAndPurchaseDetails?: { expenseAccountId: string; incomeAccountId: string; preferredVendorId?: string; purchaseCost?: string; purchaseDescription?: string; purchaseTaxCodeId?: string; salesDescription?: string; salesPrice?: string; };',
      'salesOrPurchaseDetails?: { postingAccountId: string; description?: string; price?: string; pricePercentage?: string; };',
