      'salesAndPurchaseDetails?: { expenseAccountId?: string; incomeAccountId?: string; preferredVendorId?: string; purchaseCost?: string; purchaseDescription?: string; purchaseTaxCodeId?: string; salesDescription?: string; salesPrice?: string; updateExistingTransactionsExpenseAccount?: boolean; updateExistingTransactionsIncomeAccount?: boolean; };',
      'salesOrPurchaseDetails?: { description?: string; postingAccountId?: string; price?: string; pricePercentage?: string; updateExistingTransactionsAccount?: boolean; };',
