      'exchangeRate?: number;',
      "expenseLines?: { accountId?: string; amount?: string; billingStatus?: 'billable' | 'has_been_billed' | 'not_billable'; classId?: string; customFields?: { name: string; ownerId: string; value: string; }[]; memo?: string; payeeId?: string; salesRepresentativeId?: string; salesTaxCodeId?: string; }[];",
